sys_script_include.script:
var IncentNowValidationEngine = Class.create();
IncentNowValidationEngine.prototype = {

    initialize: function() {},

    /**
     * Main entry point
     */
    validateRun: function(importRunSysId) {

        var runGR = new GlideRecordSecure('x_ctans_incentnow_import_run');
        if (!runGR.get(importRunSysId)) {
            throw "Invalid Import Run ID";
        }

        var stagingGR = new GlideRecordSecure('x_ctans_incentnow_data_lake_staging');
        stagingGR.addQuery('import_run', importRunSysId);
        stagingGR.query();

        var total = 0;
        var valid = 0;
        var invalid = 0;

        while (stagingGR.next()) {

            total++;

            var result = this._validateRow(stagingGR);

            if (result.isValid) {

                stagingGR.setValue("is_valid", true);
                stagingGR.setValue("validation_status", "Valid");
                stagingGR.setValue("validation_error", "");
                valid++;

            } else {

                stagingGR.setValue("is_valid", false);
                stagingGR.setValue("validation_status", "Invalid");
                stagingGR.setValue("validation_error", result.message);
                invalid++;

                this._logRowError(importRunSysId, stagingGR, result.message);
            }

            stagingGR.update();
        }

        // Update Import Run metrics
        runGR.setValue("total_row_count", total);
        runGR.setValue("valid_row_count", valid);
        runGR.setValue("invalid_row_count", invalid);
        runGR.setValue("validation_completed_at", new GlideDateTime());
        runGR.update();

        return {
            total: total,
            valid: valid,
            invalid: invalid
        };
    },


    /**
     * Row-Level Validation
     */
    _validateRow: function(stagingGR) {

        var payload;

        // 1️⃣ JSON Validation
        try {
            payload = JSON.parse(stagingGR.getValue("raw_json"));
        } catch (e) {
            return {
                isValid: false,
                message: "Malformed JSON payload"
            };
        }

        // 2️⃣ Basic Structural Check (optional but recommended)
        if (typeof payload !== "object" || payload === null) {
            return {
                isValid: false,
                message: "Invalid JSON structure"
            };
        }

        return {
            isValid: true
        };
    },


    /**
     * Log row-level error
     */
    _logRowError: function(runId, stagingGR, message) {

        var errGR = new GlideRecordSecure('x_ctans_incentnow_import_error');
        errGR.initialize();
        errGR.setValue("import_run", runId);
        errGR.setValue("staging_record", stagingGR.getUniqueValue());
        errGR.setValue("row_number", stagingGR.getValue("row_number"));
        errGR.setValue("error_scope", "ROW");
        errGR.setValue("error_message", message);
        errGR.setValue("raw_payload", stagingGR.getValue("raw_json"));
        errGR.insert();
    },

    type: 'IncentNowValidationEngine'
};
